struct AgentContextRequest<'a> {
    db: &'a Database,
    database: &'a Path,
    timeout_secs: u64,
    user_agent: String,
    profile: AgentProfile,
    limit: usize,
    format: OutputFormat,
    no_collect: bool,
}

struct DecisionPackRequest<'a> {
    db: &'a Database,
    database: &'a Path,
    timeout_secs: u64,
    user_agent: String,
    workflow: WorkflowKind,
    limit: usize,
    history_limit: usize,
    format: OutputFormat,
    no_collect: bool,
}

#[tokio::main]
async fn main() -> Result<()> {
    let cli = Cli::parse();
    let db = Database::open(&cli.database)?;
    db.init()?;

    match cli.command {
        Command::InitDb => {
            println!("SQLite schema ready: {}", cli.database.display());
        }
        Command::Collect { source } => {
            let batch_id = new_batch_id("collect");
            db.start_collection_batch(
                &batch_id,
                "collect",
                None,
                Some(source_selector_label(source)),
            )?;
            let client = reqwest::Client::builder()
                .use_native_tls()
                .timeout(Duration::from_secs(cli.timeout_secs))
                .user_agent(cli.user_agent.clone())
                .build()?;
            let ctx = CollectorContext {
                db: &db,
                client,
                user_agent: cli.user_agent,
                batch_id: Some(batch_id.clone()),
                profile: None,
                selector: None,
            };
            let report = run_collectors(&ctx, source).await?;
            db.finish_collection_batch(&batch_id, report.ok_sources, report.warn_sources)?;
            println!(
                "collection finished: {} sources ok, {} sources warned/failed, batch_id={}, database={}",
                report.ok_sources,
                report.warn_sources,
                batch_id,
                cli.database.display()
            );
        }
        Command::AgentContext {
            profile,
            limit,
            format,
            no_collect,
        } => {
            run_agent_context(AgentContextRequest {
                db: &db,
                database: &cli.database,
                timeout_secs: cli.timeout_secs,
                user_agent: cli.user_agent,
                profile,
                limit,
                format,
                no_collect,
            })
            .await?;
        }
        Command::DecisionPack {
            workflow,
            limit,
            history_limit,
            format,
            no_collect,
        } => {
            run_decision_pack(DecisionPackRequest {
                db: &db,
                database: &cli.database,
                timeout_secs: cli.timeout_secs,
                user_agent: cli.user_agent,
                workflow,
                limit,
                history_limit,
                format,
                no_collect,
            })
            .await?;
        }

